    62→
    63→**New Cross-Platform Implementation:**
    64→
    65→```typescript
    66→import * as fs from 'fs';
    67→import * as path from 'path';
    68→import * as os from 'os';
    69→import { spawnSync } from 'child_process';
    70→import * as readline from 'readline';
    71→
    72→const PLATFORM = process.platform;
    73→const IS_WINDOWS = PLATFORM === 'win32';
    74→const IS_MAC = PLATFORM === 'darwin';
    75→const IS_LINUX = PLATFORM === 'linux';
    76→
    77→const HOME = IS_WINDOWS
    78→  ? process.env.USERPROFILE || os.homedir()
    79→  : process.env.HOME || os.homedir();
    80→
    81→const CLAUDE_DIR = path.join(HOME, '.claude');
    82→
    83→// Cross-platform permission setting
    84→function setPermissions(targetDir: string): void {
    85→  if (IS_WINDOWS) {
    86→    // Windows: Use icacls if needed, or skip (default permissions usually OK)
    87→    console.log('Setting Windows permissions...');
    88→    // Optionally: run icacls command
    89→    spawnSync('icacls', [targetDir, '/grant', `${process.env.USERNAME}:(OI)(CI)F`], {
    90→      shell: true
    91→    });
    92→  } else {
    93→    // Unix: chmod
    94→    spawnSync('chmod', ['-R', '755', targetDir]);
    95→    spawnSync('chown', ['-R', `${process.env.USER}:${process.env.USER}`, targetDir]);
    96→  }
    97→}
    98→
    99→// Cross-platform file search
   100→function findExecutableFiles(dir: string, pattern: string): string[] {
   101→  const results: string[] = [];
   102→
   103→  function walk(currentPath: string) {
   104→    const files = fs.readdirSync(currentPath);
   105→    for (const file of files) {
   106→      const fullPath = path.join(currentPath, file);
   107→      const stat = fs.statSync(fullPath);
   108→
   109→      if (stat.isDirectory()) {
   110→        walk(fullPath);
   111→      } else if (file.match(pattern)) {
   112→        results.push(fullPath);
   113→      }
   114→    }
   115→  }
   116→
   117→  walk(dir);
   118→  return results;
   119→}
   120→
   121→// Cross-platform executable permission
   122→function makeExecutable(filePath: string): void {
   123→  if (IS_WINDOWS) {
   124→    // Windows: check if needs .exe extension
   125→    if (!filePath.endsWith('.exe') && !filePath.endsWith('.bat') && !filePath.endsWith('.ps1')) {
   126→      const renamed = filePath + '.exe';
   127→      if (fs.existsSync(filePath) && !fs.existsSync(renamed)) {
   128→        fs.renameSync(filePath, renamed);
   129→      }
   130→    }
   131→  } else {
   132→    // Unix: chmod +x
   133→    spawnSync('chmod', ['+x', filePath]);
   134→  }
   135→}
   136→
   137→// Cross-platform Bun installation
   138→function installBun(): boolean {
   139→  if (IS_WINDOWS) {
   140→    // Windows: Use PowerShell installer
   141→    const result = spawnSync('powershell', [
   142→      '-Command',
   143→      'irm bun.sh/install.ps1 | iex'
   144→    ], { shell: true });
   145→
   146→    return result.status === 0;
   147→  } else {
   148→    // Unix: Use curl with bash
   149→    const result = spawnSync('curl', ['-fsSL', 'https://bun.sh/install'], {
   150→      stdio: 'pipe'
   151→    });
   152→
   153→    if (result.status === 0) {
   154→      const installScript = spawnSync('bash', ['-'], {
   155→        input: result.stdout
   156→      });
   157→      return installScript.status === 0;
   158→    }
   159→  }
   160→
   161→  return false;
   162→}
   163→
   164→// Cross-platform shell reloading
   165→function reloadShell(): void {
   166→  console.log('\n⚠️  Please restart your terminal/shell for changes to take effect.');
   167→
   168→  if (IS_MAC) {
   169→    console.log('   Run: source ~/.zshrc');
   170→  } else if (IS_LINUX) {
   171→    console.log('   Run: source ~/.bashrc or source ~/.zshrc');
   172→  } else if (IS_WINDOWS) {
   173→    console.log('   Close and reopen PowerShell or Command Prompt');
   174→    console.log('   Or run: refreshenv');
   175→  }
   176→}
   177→
   178→// Main installation function
   179→async function install(): Promise<void> {
   180→  console.log('🤖 PAI v2.5 Installation Wizard');
   181→  console.log(`Platform: ${PLATFORM}`);
   182→
   183→  // Get user information
   184→  const rl = readline.createInterface({
   185→    input: process.stdin,
   186→    output: process.stdout
   187→  });
   188→
   189→  const name = await question(rl, 'Your name: ');
   190→  const projectsDir = await question(rl, 'Projects directory (default: ~/Projects): ', '~/Projects');
   191→
   192→  rl.close();
   193→
   194→  // Create directories
   195→  console.log('\n📁 Creating directories...');
   196→  const dirs = [
   197→    CLAUDE_DIR,
   198→    path.join(CLAUDE_DIR, 'MEMORY'),
   199→    path.join(CLAUDE_DIR, 'WORK'),
   200→    path.join(CLAUDE_DIR, 'STATE'),
   201→    path.join(CLAUDE_DIR, 'USER')
   202→  ];
   203→
   204→  for (const dir of dirs) {
   205→    if (!fs.existsSync(dir)) {
   206→      fs.mkdirSync(dir, { recursive: true });
   207→      console.log(`  Created: ${dir}`);
   208→    }
   209→  }
   210→
   211→  // Set permissions
   212→  console.log('\n🔐 Setting permissions...');
   213→  setPermissions(CLAUDE_DIR);
   214→
   215→  // Find and make executable files executable
   216→  console.log('\n🔧 Setting executable permissions...');
   217→  const execFiles = findExecutableFiles(CLAUDE_DIR, '\\.(ts|js|sh|py)$');
   218→  for (const file of execFiles) {
   219→    makeExecutable(file);
   220→  }
   221→
   222→  // Create settings.json
   223→  console.log('\n⚙️  Creating configuration...');
   224→  const settings = {
   225→    daidentity: {
   226→      name: 'PAI',
   227→      version: '2.5.0'
   228→    },
   229→    principal: {
   230→      name: name,
   231→      timezone: Intl.DateTimeFormat().resolvedOptions().timeZone
   232→    },
   233→    projects: {
   234→      defaultDirectory: path.resolve(HOME, projectsDir.replace('~', HOME))
   235→    },
   236→    platform: PLATFORM,
   237→    installDate: new Date().toISOString()
   238→  };
   239→
   240→  fs.writeFileSync(
   241→    path.join(CLAUDE_DIR, 'settings.json'),
   242→    JSON.stringify(settings, null, 2),
   243→    'utf8'
   244→  );
   245→
   246→  // Configure shell
   247→  console.log('\n🐚 Configuring shell...');
   248→  if (IS_WINDOWS) {
   249→    configurePowerShell();
   250→  } else {
   251→    configureUnixShell();
   252→  }
   253→
   254→  console.log('\n✅ Installation complete!');
   255→  reloadShell();
   256→}
   257→
   258→function question(rl: readline.Interface, query: string, defaultVal?: string): Promise<string> {
   259→  return new Promise((resolve) => {
   260→    rl.question(`${query}${defaultVal ? ` [${defaultVal}]` : ''}`, (answer) => {
   261→      resolve(answer || defaultVal || '');
   262→    });
   263→  });
   264→}
   265→
   266→// PowerShell configuration
   267→function configurePowerShell(): void {
   268→  const powershellConfig = `
   269→# PAI v2.5 Configuration
   270→export PAI_HOME="$env:USERPROFILE\\.claude"
   271→export PATH="$PATH;$PAI_HOME\\bin"
   272→`;
   273→
   274→  const profilePath = path.join(HOME, 'Documents', 'PowerShell', 'Microsoft.PowerShell_profile.ps1');
   275→
   276→  try {
   277→    let content = '';
   278→    if (fs.existsSync(profilePath)) {
   279→      content = fs.readFileSync(profilePath, 'utf8');
   280→    }
   281→
   282→    if (!content.includes('PAI v2.5')) {
   283→      fs.appendFileSync(profilePath, powershellConfig, 'utf8');
   284→      console.log('  Added PAI configuration to PowerShell profile');
   285→    }
   286→  } catch (error) {
   287→    console.warn('  Could not configure PowerShell profile:', error.message);
   288→  }
   289→}
   290→
   291→// Unix shell configuration
   292→function configureUnixShell(): void {
   293→  const shellConfig = `
   294→# PAI v2.5 Configuration
   295→export PAI_HOME="$HOME/.claude"
   296→export PATH="$PATH:$PAI_HOME/bin"
   297→`;
   298→
   299→  const zshrcPath = path.join(HOME, '.zshrc');
   300→  const bashrcPath = path.join(HOME, '.bashrc');
   301→
   302→  if (fs.existsSync(zshrcPath)) {
   303→    let content = fs.readFileSync(zshrcPath, 'utf8');
   304→    if (!content.includes('PAI v2.5')) {
   305→      fs.appendFileSync(zshrcPath, shellConfig, 'utf8');
   306→      console.log('  Added PAI configuration to ~/.zshrc');
   307→    }
   308→  } else if (fs.existsSync(bashrcPath)) {
   309→    let content = fs.readFileSync(bashrcPath, 'utf8');
   310→    if (!content.includes('PAI v2.5')) {
   311→      fs.appendFileSync(bashrcPath, shellConfig, 'utf8');
   312→      console.log('  Added PAI configuration to ~/.bashrc');
   313→    }
   314→  }
   315→}
   316→
   317→install().catch(console.error);
