   913→```typescript
   914→// .claude/lib/platform.ts
   915→export const PLATFORM = process.platform;
   916→export const IS_WINDOWS = PLATFORM === 'win32';
   917→export const IS_MAC = PLATFORM === 'darwin';
   918→export const IS_LINUX = PLATFORM === 'linux';
   919→
   920→export const HOME = IS_WINDOWS
   921→  ? process.env.USERPROFILE || require('os').homedir()
   922→  : process.env.HOME || require('os').homedir();
   923→
   924→export const CLAUDE_DIR = require('path').join(HOME, '.claude');
   925→
   926→export function getCommand(command: string): string {
   927→  // Map Unix commands to Windows equivalents
   928→  const commandMap: Record<string, string> = {
   929→    'ls': IS_WINDOWS ? 'dir' : 'ls',
   930→    'cat': IS_WINDOWS ? 'type' : 'cat',
   931→    'rm': IS_WINDOWS ? 'del' : 'rm',
   932→    'cp': IS_WINDOWS ? 'copy' : 'cp',
   933→    'mv': IS_WINDOWS ? 'move' : 'mv',
   934→    'ps': IS_WINDOWS ? 'tasklist' : 'ps',
   935→    'kill': IS_WINDOWS ? 'taskkill' : 'kill',
   936→  };
   937→
   938→  return commandMap[command] || command;
