// Cross-platform file search (replaces Unix find)
function findExecutableFiles(dir: string, patterns: string[] = ['*.ts', '*.sh', '*.py']): string[] {
  const results: string[] = [];

  function walk(currentPath: string) {
    try {
      const files = readdirSync(currentPath);
      for (const file of files) {
        const fullPath = join(currentPath, file);
        try {
          const stat = require('fs').statSync(fullPath);

          if (stat.isDirectory()) {
            walk(fullPath);
          } else {
            // Check if file matches any pattern
            for (const pattern of patterns) {
              const regex = new RegExp(`^${pattern.replace('*', '.*')}$`);
              if (regex.test(file)) {
                results.push(fullPath);
                break;
              }
            }
          }
        } catch (e) {
          // Skip files we can't read
        }
      }
    } catch (e) {
      // Skip directories we can't read
    }
  }

  walk(dir);
  return results;
}

// Cross-platform executable permission
function makeExecutable(filePath: string): void {
  if (IS_WINDOWS) {
    // Windows: Files are executable by extension (.exe, .bat, .ps1)
    // For other files, no action needed (Git handles permissions)
    return;
  } else {
    // Unix: chmod +x
    try {
      execSync(`chmod +x "${filePath}"`, { stdio: 'pipe' });
    } catch (e) {
      // Ignore errors
    }
  }
}

